INSERT INTO contract_templates (contract_type, jurisdiction, version, title, preamble, recitals, clauses, signature_block, placeholders, is_active, metadata) VALUES (
  'freelance_service',
  'us_texas',
  1,
  'Freelance Services Agreement (Texas)',
  'This Freelance Services Agreement (the "Agreement") is entered into as of {{effective_date}} (the "Effective Date"), by and between {{party_a_company}} ("Client"), with address at {{party_a_address}}, and {{party_b_name}} doing business as {{party_b_company}} ("Freelancer"), with address at {{party_b_address}}.',
  'WHEREAS, Client wishes to engage Freelancer to provide certain freelance services;
WHEREAS, Freelancer wishes to provide such services on the terms set out in this Agreement;
NOW, THEREFORE, in consideration of the mutual covenants herein, the parties agree as follows:',
  '[{"id":"services","title":"1. SERVICES","content":"1.1 Services. Freelancer shall provide the services described in {{services_description}} (the \"Services\").\n\n1.2 Standard. Freelancer shall perform the Services professionally, meeting applicable industry standards.\n\n1.3 Deliverables. Freelancer shall deliver any work products as specified in {{services_description}}.\n\n1.4 Timeline. Freelancer shall complete the Services within the timeframe set out in {{services_description}}.\n\n1.5 Changes. Changes to the Services must be agreed in writing.","type":"standard","order":1},{"id":"payment","title":"2. PAYMENT","content":"2.1 Fees. Client shall pay Freelancer: (a) a project fee of {{payment_amount}}; and/or (b) {{hourly_rate}} per hour, as specified in {{services_description}}.\n\n2.2 Invoicing. Freelancer shall invoice Client as set out in {{services_description}}, or upon completion if not specified.\n\n2.3 Payment Terms. Client shall pay invoices within 30 days of receipt. Late payments accrue interest at 1.5% per month or the maximum rate permitted by Texas law.\n\n2.4 Expenses. Freelancer is responsible for all expenses unless pre-approved in writing.\n\n2.5 Taxes. Freelancer is responsible for all taxes on fees received. Texas does not impose state income tax on individuals. Client will not withhold payroll taxes.","type":"standard","order":2},{"id":"freelancer_status","title":"3. FREELANCER STATUS","content":"3.1 Independent Contractor. Freelancer is an independent contractor, not an employee or agent of Client.\n\n3.2 Control. Freelancer determines how, when, and where to perform the Services, subject to meeting agreed deliverables and deadlines.\n\n3.3 Texas Classification. The Parties intend that Freelancer be classified as an independent contractor under Texas law.\n\n3.4 Equipment. Freelancer shall provide their own equipment, tools, and materials.\n\n3.5 No Exclusivity. Freelancer may work for other clients, provided this does not conflict with obligations under this Agreement.\n\n3.6 No Benefits. Freelancer is not entitled to employee benefits.","type":"standard","order":3},{"id":"term","title":"4. TERM AND TERMINATION","content":"4.1 Term. This Agreement runs from the Effective Date until {{expiration_date}}, or until the Services are completed, unless terminated earlier.\n\n4.2 Termination for Convenience. Either party may terminate by giving {{notice_period}} days'' written notice.\n\n4.3 Termination for Cause. Either party may terminate immediately if the other: (a) materially breaches and fails to cure within 7 days of notice; (b) becomes insolvent; or (c) commits fraud.\n\n4.4 Effect. Upon termination: (a) Freelancer stops work and delivers completed work; (b) Client pays for work completed.","type":"standard","order":4},{"id":"intellectual_property","title":"5. INTELLECTUAL PROPERTY","content":"5.1 Work Product. \"Work Product\" means all materials created by Freelancer in performing the Services.\n\n5.2 Assignment. Upon full payment, Freelancer assigns all intellectual property rights in the Work Product to Client.\n\n5.3 Background IP. Freelancer retains pre-existing IP (\"Background IP\"). If Background IP is included in Work Product, Freelancer grants Client a perpetual, royalty-free license to use it.\n\n5.4 Moral Rights. Freelancer waives moral rights in the Work Product to the extent permitted by law.\n\n5.5 Portfolio. Unless otherwise agreed, Freelancer may display completed Work Product in their portfolio for self-promotion.","type":"negotiable","order":5},{"id":"confidentiality","title":"6. CONFIDENTIALITY","content":"6.1 Confidential Information. Each party shall keep confidential any non-public information received from the other that is designated confidential or should reasonably be understood as confidential.\n\n6.2 Obligations. Confidential Information shall be: (a) used only for this Agreement; (b) protected with reasonable care; (c) not disclosed except to those who need to know.\n\n6.3 Exclusions. Excludes information that is: public, already known, received from third parties, or independently developed.\n\n6.4 Defend Trade Secrets Act Notice. Pursuant to 18 U.S.C. § 1833(b), an individual shall not be held liable for disclosure of a trade secret made in confidence for reporting suspected violations of law.\n\n6.5 Duration. Confidentiality obligations survive termination for {{confidentiality_period}} years.","type":"standard","order":6},{"id":"warranties","title":"7. WARRANTIES","content":"7.1 Freelancer Warranties. Freelancer warrants that: (a) they have authority to enter this Agreement; (b) Services will be performed professionally; (c) Work Product will be original and not infringe third-party rights; (d) they have the right to assign IP in Work Product.\n\n7.2 Client Warranties. Client warrants that: (a) they have authority to enter this Agreement; (b) materials provided to Freelancer do not infringe third-party rights.\n\n7.3 Disclaimer. Except as stated, neither party makes additional warranties.","type":"standard","order":7},{"id":"liability","title":"8. LIABILITY","content":"8.1 Limitation. Neither party is liable for indirect or consequential damages. Total liability is limited to the fees paid or payable under this Agreement.\n\n8.2 Exceptions. Nothing limits liability for fraud, willful misconduct, or matters that cannot be limited by law.\n\n8.3 Insurance. Freelancer is advised to maintain appropriate professional liability insurance.","type":"negotiable","order":8},{"id":"general","title":"9. GENERAL PROVISIONS","content":"9.1 Governing Law. This Agreement is governed by the laws of the State of Texas, without regard to conflict of laws principles.\n\n9.2 Venue. The Parties consent to exclusive jurisdiction of the state and federal courts in {{venue_county}} County, Texas.\n\n9.3 Notices. Notices shall be in writing, delivered by hand, mail, or email.\n\n9.4 Assignment. Neither party may assign without consent, except to a successor entity.\n\n9.5 Entire Agreement. This Agreement is the entire agreement. Amendments must be in writing.\n\n9.6 Severability. Invalid provisions are enforced to the maximum extent permitted.\n\n9.7 Waiver. Waivers must be in writing.\n\n9.8 Force Majeure. Neither party is liable for delays beyond reasonable control.\n\n9.9 Counterparts. May be signed in counterparts, including electronically under Texas Business and Commerce Code, Chapter 322.","type":"standard","order":9}]'::jsonb,
  'IN WITNESS WHEREOF, the parties have executed this Agreement as of {{signature_date}}.

CLIENT:
{{party_a_company}}

By: ______________________________
