category":"dates","type":"date","required":false},{"id":"venue_county","token":"{{venue_county}}","label":"Venue County","description":"Texas county for legal venue","category":"terms","type":"text","required":true},{"id":"notice_period","token":"{{notice_period}}","label":"Notice Period","description":"Days notice for termination","category":"terms","type":"number","required":false},{"id":"confidentiality_period","token":"{{confidentiality_period}}","label":"Confidentiality Period","description":"Years of confidentiality obligation","category":"terms","type":"number","required":false},{"id":"hourly_rate","token":"{{hourly_rate}}","label":"Hourly Rate","description":"Rate per hour","category":"financial","type":"currency","required":false},{"id":"payment_amount","token":"{{payment_amount}}","label":"Project Fee","description":"Total project fee","category":"financial","type":"currency","required":false},{"id":"services_description","token":"{{services_description}}","label":"Services","description":"Description of services","category":"project","type":"textarea","required":false}]'::jsonb,
